var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BALLISTA_FAW_NULL_NULL","text":{"KOREA":"......시스템 동기화 성공.","JPN":"……システム同期に成功。","ENG":"System synchronization succeeded.","TWN":"……系統同步成功。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BALLISTA_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_06"},{"id":"L3_1","type":"dialog","speaker":"BALLISTA_FAW_NULL_NULL","text":{"KOREA":"새로운 명령권자 등록을 확인했습니다.","JPN":"新しい命令権者の登録を確認しました。","ENG":"The new commander acknowledged.","TWN":"已確認新的命令權者登記。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BALLISTA_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BALLISTA_FAW_NULL_NULL","text":{"KOREA":"안녕하세요, 시그마님?","JPN":"こんにちは、シグマさま。","ENG":"Hello, Sigma.","TWN":"你好，西格瑪？"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BALLISTA_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"안녕!","JPN":"ハロー！","ENG":"Hi!","TWN":"你好！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"갇혀있느라 답답했지? 나랑 함께 여길 벗어나자!","JPN":"ずっと拘束されて辛かったよね？　私と一緒に\\nここを離れよう！","ENG":"You must hate being stuck in this place. Let's get out of here with me.","TWN":"被關在這裡一定很痛苦吧？快跟我離開這裡！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"할아버지, 이걸로 모두 구해낸 거 같아!","JPN":"おじいちゃん、これで全員助け出したみたい！","ENG":"Grandpa, he was the last one to save.","TWN":"爺爺，好像所有人都被救出來了！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"음! 훌륭하군. 이제 함께 돌아가도록 하지.","JPN":"うむ！　すばらしいぞ。じゃあ、みんなで帰るとするか。","ENG":"Ah, excellent. Now, let's go back together.","TWN":"嗯！太好了，一起回去吧。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"......음? 잠깐.","JPN":"……む？　ちょっと待て。","ENG":"Mm? Wait.","TWN":"……嗯？等等。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"무언가 위험한 것이 다가오는 것 같군.","JPN":"何か危険なものが近づいているようだ。","ENG":"Something dangerous is approaching.","TWN":"好像有危險的東西正在靠近。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"다들 뒤로 물러서게!","JPN":"みんな後ろに下がれ！","ENG":"Everyone, step back!","TWN":"都退後！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"난동을 피우는 건 여기까지다, 이 쇳덩어리들!","JPN":"暴れるのはここまでだ、この鉄の塊どもめ！","ENG":"Playtime is over, you tin cans.","TWN":"到此為止了，鐵塊們！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"내 콜렉션 주제에 멋대로 날뛰다니, 분수를 모르는군.","JPN":"俺のコレクションのくせに好き勝手に暴れだすなんてな。\\n身の程知らずにもほどがある。","ENG":"You all belong to me, and it's time you accept that.","TWN":"區區收藏品還如此撒野，不自量力。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"저항하는 녀석들은 싸그리 녹여서 고철로 재활용해주마.","JPN":"抵抗する奴らは全員まとめて溶かして、役立つ何かに\\nリサイクルしてやるぞ。","ENG":"Fight me, and I'll crush you and send you to the junkyard.","TWN":"誰敢反抗我就把它熔化後回收再利用。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"우릴 납치한 이 해적들의 우두머리로군!","JPN":"我々をさらった海賊団の親玉だな！","ENG":"She's the leader of the pirates that abducted us!","TWN":"他就是綁架我們的海盜頭目！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"그런데 저 자가 탄 아라크네는 이 친구들보다 꽤 큰 것 같은데?","JPN":"ところで、あやつが乗っているアラクネは味方の\\nアラクネよりもずいぶん大きいようだな。","ENG":"By the way, her Arachne is much bigger than these girls here.","TWN":"但是他乘坐的阿拉克涅好像比這些夥計大了不少喔？"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ARACHNE_FAW_NULL_NULL","text":{"KOREA":"대상 아라크네 개체로부터 우호적 신호가 감지되지 않습니다. 주의하십시오.","JPN":"相手のアラクネ個体から友好的なシグナルが\\n検出されません。ご注意ください。","ENG":"I don't detect any friendly signals from the target Arachne. Please be careful.","TWN":"未感知到對方阿拉克涅個體的友好信號，請注意。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARACHNE_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"하하하, 내가 할 줄 아는 게 고작 기계를 빼앗는 것뿐이라 생각했다면 오산이다.","JPN":"ハハハ、俺が機械を奪うことしかできないと思ってたなら\\n大きな間違いだ。","ENG":"Hah hah hah! If you thought I only knew how to steal machines, you're mistaken.","TWN":"哈哈哈！如果以為我只會掠奪機械就大錯特錯了。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"내 진정한 장기는 개조를 통해 기계의 능력을 극한까지 끌어내는 거니까!","JPN":"俺の真の得意技は、改造で機械の能力を極限まで\\n引き出すことだからな！","ENG":"My real specialty is modifying machines to the extreme.","TWN":"我真正的能力是通過改造將機械的能力發揮到極限！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"덕분에 몇 번 써먹고 나면 망가진다는 문제가 있긴 하지만...... 그런 건 내가 알 바 아니지!","JPN":"何度か使うと壊れるという弱点はあるが……\\nそんなの知ったこっちゃない！","ENG":"The only problem is the machines that I modify don't last long, but I can always grab more!","TWN":"雖然使用幾次後會因為副作用受損……但我管不了那麼多！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"자! 이 몸이 손수 개조한 <color=#ffd34c>불거머리</color>의 힘을 지금부터 보여주마!","JPN":"さあ！　俺様が改造した<color=#ffd34c>ファイヤーリーチ</color>の力を\\n知らしめてやろう！","ENG":"Now, let me show you the power of <color=#ffd34c>Fire Leech</color> that I personally modified.","TWN":"來！我讓你們瞧瞧我親手改造的<color=#ffd34c>火焰蛭</color>的力量！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"으음, 집에 일찍 안 들어가면 아빠가 걱정할 텐데......","JPN":"むむ、早く家に帰らないとパパが心配しちゃうのに……","ENG":"Mm, Daddy will be worried if I'm not home soon...","TWN":"嗯，如果不快點回家，爸爸會擔心的……"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"좋아! 잠깐 정도는 같이 놀아줄게.","JPN":"いいよ！　ちょっとだけ遊んであげるね。","ENG":"But okay, I think I can play with you for a while.","TWN":"好！我就再陪你玩一玩。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"다들 들었나! 전 기체! 전투를 준비하게!","JPN":"みんな聞こえたか！　全員、戦闘に備えよ！","ENG":"Guys, did you hear that? Everyone, get ready to fight!","TWN":"各位都聽到了吧！全部機體！準備戰鬥！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};